code.Java:
import java.util.Scanner;

// Define the class for a binary tree node
class Node {
    int data;
    Node left;
    Node right;

    public Node(int data) {
        this.data = data;
        this.left = null;
        this.right = null;
    }
}

public class BinaryTree {
    // Function to print the binary tree
    public static void printTree(Node root, int level) {
        if (root == null) return;
        printTree(root.right, level + 1);
        for (int i = 0; i < level; i++) System.out.print(" ");
        System.out.println(root.data);
        printTree(root.left, level + 1);
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter the number of nodes: ");
        int n = scanner.nextInt();
        int[] values = new int[n];
        System.out.print("Enter the node values: ");
        for (int i = 0; i < n; i++) values[i] = scanner.nextInt();
        Node root = new Node(values[0]);
        Node[] nodes = new Node[n];
        nodes[0] = root;
        for (int i = 1; i < n; i++) {
            Node newNode = new Node(values[i]);
            nodes[i] = newNode;
            if (i % 2 == 1) nodes[(i - 1) / 2].left = newNode;
            else nodes[(i - 1) / 2].right = newNode;
        }
        printTree(root, 0);
    }
}

