class Node:
    def __init__(self, data):
        self.data = data
        self.left = None
        self.right = None

# Function to print the binary tree
def print_tree(root, level):
    if root is None:
        return
    print_tree(root.right, level + 1)
    print(' ' * level + str(root.data))
    print_tree(root.left, level + 1)

# Main function
def main():
    n = int(input("Enter the number of nodes: "))
    values = list(map(int, input("Enter the node values: ").split()))
    root = Node(values[0])
    nodes = [root]
    for i in range(1, n):
        new_node = Node(values[i])
        nodes.append(new_node)
        if i % 2 == 1:
            nodes[(i - 1) // 2].left = new_node
        else:
            nodes[(i - 1) // 2].right = new_node
    print_tree(root, 0)

if __name__ == '__main__':
    main()

