// Function to print the binary tree
function printTree(root, level) {
    if (root === null) return;
    printTree(root.right, level + 1);
    console.log(' '.repeat(level) + root.data);
    printTree(root.left, level + 1);
}

// Main function
function main() {
    const readline = require('readline').createInterface({
        input: process.stdin,
        output: process.stdout
    });
    readline.question('Enter the number of nodes: ', n => {
        readline.question('Enter the node values: ', values => {
            values = values.split(' ').map(Number);
            const root = new Node(values[0]);
            const nodes = [root];
            for (let i = 1; i < n; i++) {
                const newNode = new Node(values[i]);
                nodes.push(newNode);
                if (i % 2 === 1) nodes[Math.floor((i - 1) / 2)].left = newNode;
                else nodes[Math.floor((i - 1) / 2)].right = newNode;
            }
            printTree(root, 0);
            readline.close();
        });
    });
}

main();

